const msg = $input.first().json;
const text = (msg.message?.text || msg.text || '').trim();
const chatId = msg.message?.chat?.id || msg.chat?.id || '';
const firstName = msg.message?.from?.first_name || msg.from?.first_name || 'Customer';
const upper = text.toUpperCase();
const statusMatch  = upper.match(/^STATUS\s+(\d+)/);
const cancelMatch  = upper.match(/^CANCEL\s+(\d+)/);
const startMatch   = upper.match(/^\/START/);
const helpMatch    = upper.match(/^\/HELP|^HELP/);
const menuMatch    = upper.match(/^\/MENU|^MENU/);
const myorderMatch = upper.match(/^\/MYORDERS|^MYORDERS/);
let route = 'order';
if (statusMatch)   route = 'status';
if (cancelMatch)   route = 'cancel';
if (startMatch)    route = 'start';
if (helpMatch)     route = 'help';
if (menuMatch)     route = 'menu';
if (myorderMatch)  route = 'myorders';
if (upper.match(/^READY\s+\d+/)) route = 'blocked';
console.log('ChatID:', chatId, '| Route:', route, '| Text:', text);
return [{ json: {
  chat_id: String(chatId), text, first_name: firstName, upper, route,
  queue_match: statusMatch?.[1] || cancelMatch?.[1] || null
}}];

const aiRaw = $input.first().json.output || '';
const prev = $('Route Message').first().json;
let p = null;
try { p = JSON.parse(aiRaw.trim()); } catch(e) {}
if (!p) { try { const m = aiRaw.match(/\{[\s\S]*\}/); if(m) p = JSON.parse(m[0]); } catch(e) {} }
if (!p) { p = { items: prev.text, valid: true }; }
if (!p.valid) {
  return [{ json: {
    chat_id: prev.chat_id,
    reply: "Sorry, I didn't understand that as a food order! 🤔\n\nType your order like:\n\"2 Margherita pizza + 1 Coke\"\n\nType /menu to see what we offer\nType /help for all commands.",
    is_order: false
  }}];
}
const queueNum = Math.floor(Date.now() / 1000) % 9000 + 1000;
const waitMins = 10 + Math.floor(Math.random() * 10);
const now = new Date();
const reply = `✅ Order received!\n\n📋 Order: ${p.items}\n🔢 Queue: #${queueNum}\n⏱️ Wait: ~${waitMins} mins\n\nYou'll be notified automatically when ready!\n\nCheck anytime: STATUS ${queueNum}\nTo cancel: CANCEL ${queueNum}`;
return [{ json: {
  chat_id: prev.chat_id, first_name: prev.first_name, reply,
  is_order: true, queue_number: queueNum,
  parsed_order: p.items,
  wait_mins: waitMins, status: 'Pending',
  order_time: now.toISOString(), order_date: now.toLocaleDateString('en-IN')
}}];

const routeData = $('Route Message').first().json;
const orderRow = $input.first().json;
const queueNum = routeData.queue_match;
const chatId = String(routeData.chat_id);
const hasData = orderRow && (orderRow['Queue Number'] || orderRow['Order']);
if (!hasData) {
  return [{ json: { chat_id: chatId, reply: `❌ Order #${queueNum} not found.\n\nPlease check the queue number and try again.`, can_cancel: false }}];
}
const currentStatus = orderRow['Status'] || 'Unknown';
const orderItems = orderRow['Order'] || 'your order';
const orderChatId = String(orderRow['Chat ID'] || '');
if (orderChatId !== chatId) {
  return [{ json: { chat_id: chatId, reply: `❌ You can only cancel your own orders.`, can_cancel: false }}];
}
if (currentStatus === 'Completed') {
  return [{ json: { chat_id: chatId, reply: `⚠️ Order #${queueNum} is already *Completed*.\n\n📋 Order: ${orderItems}\n\nCompleted orders cannot be cancelled.`, can_cancel: false }}];
}
if (currentStatus === 'Cancelled') {
  return [{ json: { chat_id: chatId, reply: `⚠️ Order #${queueNum} is already *Cancelled*.`, can_cancel: false }}];
}
if (currentStatus === 'Ready') {
  return [{ json: { chat_id: chatId, reply: `⚠️ Order #${queueNum} is *Ready for collection*!\n\n📋 Order: ${orderItems}\n\nPlease collect your order from the counter 😊`, can_cancel: false }}];
}
if (currentStatus === 'Preparing') {
  return [{ json: { chat_id: chatId, reply: `⚠️ Order #${queueNum} is currently being *Prepared*.\n\n📋 Order: ${orderItems}\n\nUnfortunately it cannot be cancelled at this stage.`, can_cancel: false }}];
}
return [{ json: {
  chat_id: chatId,
  reply: `✅ Order #${queueNum} has been *cancelled*.\n\n📋 Order: ${orderItems}\n\nWe're sorry for any inconvenience.`,
  can_cancel: true, queue_number: String(queueNum), order_items: orderItems
}}];

const routeData = $('Route Message').first().json;
const orderRow = $input.first().json;
const queueNum = routeData.queue_match;
const hasData = orderRow && (orderRow['Queue Number'] || orderRow['Order']);
if (!hasData) {
  return [{ json: { chat_id: String(routeData.chat_id), reply: `❌ Order #${queueNum} not found.\n\nPlease check the queue number and try again.` } }];
}
const status = orderRow['Status'] || 'Unknown';
const orderItems = orderRow['Order'] || 'Unknown order';
const name = orderRow['Name'] || '';
const orderTime = orderRow['Order Time'] || '';
const emojiMap = { 'Completed': '✅', 'Cancelled': '❌', 'Pending': '⏳', 'Ready': '🍕', 'Preparing': '👨‍🍳' };
const emoji = emojiMap[status] || '📋';
let timeStr = '';
if (orderTime) {
  try {
    const d = new Date(orderTime);
    timeStr = `\n🕐 Ordered: ${d.toLocaleTimeString('en-IN', {hour:'2-digit', minute:'2-digit'})}`;
  } catch(e) {}
}
const reply = `${emoji} *Order #${queueNum}*\n\n📋 Order: ${orderItems}\n📊 Status: *${status}*${timeStr}${name ? '\n👤 Name: ' + name : ''}`;
return [{ json: { chat_id: String(routeData.chat_id), reply } }];

const routeData = $('Route Message').first().json;
const allRows = $input.all();
const myChatId = String(routeData.chat_id);
const myOrders = allRows.filter(r => String(r.json['Chat ID'] || '') === myChatId).slice(-5).reverse();
if (myOrders.length === 0) {
  return [{ json: { chat_id: myChatId, reply: "📋 You have no orders yet.\n\nJust type your order to get started!\nType /menu to see what we offer." } }];
}
const emojiMap = { 'Completed': '✅', 'Cancelled': '❌', 'Pending': '⏳', 'Ready': '🍕', 'Preparing': '👨‍🍳' };
let reply = `📋 *Your Recent Orders:*\n\n`;
for (const r of myOrders) {
  const row = r.json;
  const status = row['Status'] || 'Unknown';
  const emoji = emojiMap[status] || '📋';
  reply += `${emoji} *#${row['Queue Number']}* — ${row['Order']}\n   ${status} | ${row['Order Date'] || ''}\n\n`;
}
return [{ json: { chat_id: myChatId, reply } }];

const row = $input.item.json;
const rowNum    = row['row_number'];
const queueNum  = String(row['Queue Number']      || '').trim();
const chatId    = String(row['Chat ID']           || '').trim();
const status    = String(row['Status']            || '').trim();
const lastSent  = String(row['Last Status Sent']  || '').trim();
const order     = String(row['Order']             || '').trim();
const name      = String(row['Name']              || '').trim();

// Skip empty rows
if (!queueNum || !chatId || chatId === '0') return null;

// Skip Pending — only notify on staff-set statuses
const notifiable = ['Preparing', 'Ready', 'Completed', 'Cancelled'];
if (!notifiable.includes(status)) return null;

// THE KEY CHECK: only notify if status is different from last time we sent
if (status === lastSent) return null;

console.log(`Row ${rowNum} | Queue #${queueNum} | ${lastSent||'(none)'} → ${status} ✅ SEND`);

return { json: { row_number: rowNum, queue_number: queueNum, chat_id: chatId, status, order, name } };

const d = $input.item.json;
const msgs = {
  'Preparing': `👨‍🍳 Your order is being *Prepared*!

📋 Order: ${d.order}
🔢 Queue: #${d.queue_number}

We'll notify you when it's ready!`,
  'Ready':     `🍕 Your order is *READY*!

📋 Order: ${d.order}
🔢 Queue: #${d.queue_number}

Please collect from the counter 😊`,
  'Completed': `✅ Order #${d.queue_number} *Completed*.

Thank you! 🙏`,
  'Cancelled': `❌ Order #${d.queue_number} *Cancelled*.

📋 Order: ${d.order}

Sorry for the inconvenience.`
};
return { json: { ...d, msg: msgs[d.status] } };

const d = $('Build Message').item.json;
const rowNum = d.row_number;
const status = d.status;
// Column H = Last Status Sent (8th column = H)
const range = `Sheet1!H${rowNum}`;
const url   = `https://sheets.googleapis.com/v4/spreadsheets/1_XaI7z844arJWhzMN2MbD6kFzHoK6yUvsY1OyE10ebM/values/${encodeURIComponent(range)}?valueInputOption=RAW`;
console.log(`Writing H${rowNum} = "${status}"`);
return { json: { ...d, _url: url, _body: { range, majorDimension:'ROWS', values:[[status]] } } };
